def parse_basic_auth(auth_header: str):
    if not auth_header:
        return None, None
    parts = auth_header.split(" ", 1)
    if len(parts) != 2 or parts[0].lower() != "basic":
        return None, None
    import base64

    try:
        raw = base64.b64decode(parts[1]).decode("utf-8")
        if ":" not in raw:
            return None, None
        cid, cs = raw.split(":", 1)
        return cid, cs
    except Exception:
        return None, None


